import type { AudioEffect } from "./BaseEffect.js";

export interface DelayParams {
  delayTime: number;
  feedback: number;
  mix: number;
}

export class DelayEffect implements AudioEffect {
  readonly name = "delay";

  private buffers: Float64Array[] = [];
  private writePositions: number[] = [];
  private _delayTime: number;
  private _feedback: number;
  private _mix: number;
  private _sampleRate: number;
  private _delaySamples: number = 0;

  constructor(sampleRate: number, channels: number, params?: Partial<DelayParams>) {
    this._sampleRate = sampleRate;
    this._delayTime = params?.delayTime ?? 200;
    this._feedback = params?.feedback ?? 0.3;
    this._mix = params?.mix ?? 0.5;
    this.initBuffers(channels);
  }

  private initBuffers(channels: number): void {
    this._delaySamples = Math.max(1, Math.round((this._delayTime / 1000) * this._sampleRate));
    this.buffers = Array.from({ length: channels }, () => new Float64Array(this._delaySamples));
    this.writePositions = Array.from({ length: channels }, () => 0);
  }

  get delayTime(): number { return this._delayTime; }
  get feedback(): number { return this._feedback; }
  get mix(): number { return this._mix; }

  setDelayTime(ms: number): void {
    this._delayTime = Math.max(1, Math.min(5000, ms));
    this.initBuffers(this.buffers.length);
  }

  setFeedback(v: number): void {
    this._feedback = Math.max(0, Math.min(1, v));
  }

  setMix(v: number): void {
    this._mix = Math.max(0, Math.min(1, v));
  }

  isActive(): boolean {
    return this._mix > 0;
  }

  process(samples: Float64Array, channels: number, _frames: number): void {
    const mix = this._mix;
    const feedback = this._feedback;
    const delay = this._delaySamples;

    if (mix <= 0 || delay <= 0) return;

    const limit = Math.min(channels, this.buffers.length);

    for (let ch = 0; ch < limit; ch++) {
      const buf = this.buffers[ch]!;
      let wp = this.writePositions[ch]!;

      for (let i = ch; i < samples.length; i += channels) {
        const input = samples[i]!;
        const readPos = (wp - delay + delay) % delay;
        const delayed = buf[readPos]!;
        samples[i] = input * (1 - mix) + delayed * mix;
        buf[wp] = input + delayed * feedback;
        wp = (wp + 1) % delay;
      }

      this.writePositions[ch] = wp;
    }
  }

  reset(): void {
    for (const buf of this.buffers) {
      buf.fill(0);
    }
    this.writePositions.fill(0);
  }
}
